const incoming = $('Webhook').first().json;
const headers = incoming.headers || {};
const body = incoming.body || {};

const incomingToken = (headers['x-admin-token'] || '').trim();
const storedToken = ($('Load Admin Token').first().json.value || '').trim();
const action = (body.action || '').trim();

if (!incomingToken || incomingToken !== storedToken) {
  return [{ json: { authorized: false, statusCode: 401, error: 'unauthorized', action: '' } }];
}

const allowed = [
  'health', 'bookings', 'templates', 'revenue',
  'revenue_add_competitor_price', 'pricing_recommendations',
  'competitor_sources', 'competitor_price_observations',
  'competitor_market_summary', 'competitor_source_update_manual',
  'pricing_recommendation_approve', 'pricing_recommendation_reject',
  'pricing_action_audit_log', 'market_history', 'add_competitor_observation', 'pricing_recommendation_export_rc', 'pricing_recommendation_mark_manual_applied', 'pricing_recommendation_mark_apply_failed',
];
if (!allowed.includes(action)) {
  return [{ json: { authorized: true, statusCode: 400, error: 'unknown_action', action } }];
}

return [{ json: { authorized: true, statusCode: 200, error: '', action } }];

const r = $input.first().json;

// Market stats from competitor_sources + observations
const mMin = r.cs_market_min ? parseFloat(r.cs_market_min) : (r.market_min ? parseFloat(r.market_min) : null);
const mMed = r.cs_market_median ? parseFloat(r.cs_market_median) : (r.market_median ? parseFloat(r.market_median) : null);
const mAvg = r.cs_market_avg ? parseFloat(r.cs_market_avg) : (r.market_avg ? parseFloat(r.market_avg) : null);
const mMax = r.cs_market_max ? parseFloat(r.cs_market_max) : (r.market_max ? parseFloat(r.market_max) : null);

return [{ json: {
  ok: true,
  action: 'revenue',
  summary: {
    total_gaps: parseInt(r.total_gaps) || 0,
    total_estimated_loss: parseFloat(r.total_estimated_loss) || 0,
    one_night_gaps: parseInt(r.one_night_gaps) || 0,
    two_night_gaps: parseInt(r.two_night_gaps) || 0,
    three_night_gaps: parseInt(r.three_night_gaps) || 0,
    competitor_count: parseInt(r.competitor_count) || 0,
    competitor_sources_count: parseInt(r.competitor_sources_count) || 0,
    active_competitors_count: parseInt(r.active_competitors_count) || 0,
    excluded_competitors_count: parseInt(r.excluded_competitors_count) || 0,
    market_min: mMin,
    market_median: mMed,
    market_avg: mAvg,
    market_max: mMax,
    latest_market_median_from_sources: mMed,
    latest_market_avg_from_sources: mAvg,
    latest_market_min_from_sources: mMin,
    latest_market_max_from_sources: mMax,
    recommendations_count: parseInt(r.recommendations_count) || 0
  },
  gap_windows: r.gap_windows ? (typeof r.gap_windows === 'string' ? JSON.parse(r.gap_windows) : r.gap_windows) : [],
  competitor_prices: r.competitor_prices ? (typeof r.competitor_prices === 'string' ? JSON.parse(r.competitor_prices) : r.competitor_prices) : [],
  latest_observations: r.latest_observations ? (typeof r.latest_observations === 'string' ? JSON.parse(r.latest_observations) : r.latest_observations) : []
}}];

const rows = $input.all().map(i => i.json);
return [{ json: {
  ok: true,
  action: 'competitor_sources',
  competitor_sources: rows,
  summary: {
    total: rows.length,
    active: rows.filter(r=>r.status==='active').length,
    excluded: rows.filter(r=>r.status==='excluded').length
  }
}}];

const rows = $input.all().map(i => i.json);
return [{ json: {
  ok: true,
  action: 'competitor_price_observations',
  observations: rows,
  count: rows.length
}}];

const r = $input.first().json;
const staleWarning = (r.fresh_observations_14d === 0)
  ? 'Все данные seed/устаревшие (> 14 дней). Рекомендуется ручная проверка цен конкурентов.'
  : null;
return [{ json: {
  ok: true,
  action: 'competitor_market_summary',
  market: {
    active_sources: r.active_sources,
    excluded_sources: r.excluded_sources,
    market_min: r.market_min ? parseFloat(r.market_min) : null,
    market_median: r.market_median ? parseFloat(r.market_median) : null,
    market_avg: r.market_avg ? parseFloat(r.market_avg) : null,
    market_max: r.market_max ? parseFloat(r.market_max) : null,
    total_observations: r.total_observations,
    fresh_observations_14d: r.fresh_observations_14d,
    latest_observed_at: r.latest_observed_at,
    stale_warning: staleWarning,
    competitor_details: r.competitor_details
  }
}}];

const body = ($('Webhook').first().json.body) || $input.first().json || {};
const id = body.competitor_source_id || body.id || null;
const price_per_night = body.price_per_night ? parseFloat(body.price_per_night) : null;
const stay_date_from = body.stay_date_from || body.date_from || null;
const stay_date_to = body.stay_date_to || body.date_to || null;
const notes = body.notes || 'manual_input via Admin API';
const confidence = body.confidence ? parseFloat(body.confidence) : 0.90;

if (!id || !price_per_night || !stay_date_from || !stay_date_to) {
  throw new Error('Missing required fields: competitor_source_id, price_per_night, stay_date_from, stay_date_to');
}

const nights = Math.round((new Date(stay_date_to) - new Date(stay_date_from)) / 86400000);

return [{json: {
  q_id: id,
  q_price: price_per_night,
  q_from: stay_date_from,
  q_to: stay_date_to,
  q_nights: nights,
  q_confidence: confidence,
  q_notes: notes
}}];

const body = ($('Webhook').first().json.body) || $input.first().json || {};
const rec_id = (body.recommendation_id || '').trim();
const reason = (body.reason || 'Одобрено владельцем').replace(/'/g, "''");
if (!rec_id) {
  return [{ json: { ok: false, error: 'recommendation_id is required' } }];
}
return [{ json: { q_rec_id: rec_id, q_reason: reason } }];

const row = $input.first().json;
if (!row || row.rows_updated === 0 || row.rows_updated === '0') {
  return [{ json: { ok: false, error: 'Recommendation not found or status is not draft/rejected', rows_updated: row.rows_updated } }];
}
return [{ json: { ok: true, action: 'pricing_recommendation_approve', rec_id: row.rec_id, audit_id: row.audit_id, previous_status: row.previous_status, new_status: 'approved' } }];

const body = ($('Webhook').first().json.body) || $input.first().json || {};
const rec_id = (body.recommendation_id || '').trim();
const reason = (body.reason || 'Отклонено владельцем').replace(/'/g, "''");
if (!rec_id) {
  return [{ json: { ok: false, error: 'recommendation_id is required' } }];
}
return [{ json: { q_rec_id: rec_id, q_reason: reason } }];

const row = $input.first().json;
if (!row || row.rows_updated === 0 || row.rows_updated === '0') {
  return [{ json: { ok: false, error: 'Recommendation not found or status is not draft/approved', rows_updated: row.rows_updated } }];
}
return [{ json: { ok: true, action: 'pricing_recommendation_reject', rec_id: row.rec_id, audit_id: row.audit_id, previous_status: row.previous_status, new_status: 'rejected' } }];

const row = $input.first().json;
const data = Array.isArray(row.audit_data) ? row.audit_data : [];
return [{ json: { ok: true, action: 'pricing_action_audit_log', count: data.length, data: data } }];

const body = $('Webhook').first().json.body || {};
const srcId   = (body.competitor_source_id || '').trim().replace(/'/g, "''");
const dtFrom  = (body.date_from || '').trim().replace(/'/g, "''");
const dtTo    = (body.date_to   || '').trim().replace(/'/g, "''");
const lim     = parseInt(body.limit) > 0 && parseInt(body.limit) <= 200 ? parseInt(body.limit) : 50;
const latestOnly = body.latest_only === true || body.latest_only === 'true';

const where = [];
if (srcId) where.push(`cpo.competitor_source_id::text = '${srcId}'`);
if (dtFrom) where.push(`cpo.stay_date_from >= '${dtFrom}'::date`);
if (dtTo)   where.push(`cpo.stay_date_to   <= '${dtTo}'::date`);
const w = where.length > 0 ? 'WHERE ' + where.join(' AND ') : '';

const sel = `cpo.id::text AS id, cs.name AS competitor_name, cs.similarity_score,
  cs.source_platform, cs.url AS competitor_url,
  to_char(cpo.observed_at, 'YYYY-MM-DD"T"HH24:MI:SS"Z"') AS observed_at,
  to_char(cpo.stay_date_from,'YYYY-MM-DD') AS stay_date_from,
  to_char(cpo.stay_date_to,  'YYYY-MM-DD') AS stay_date_to,
  cpo.nights, cpo.price_per_night::float, cpo.confidence::float,
  cpo.collection_method, cpo.notes,
  to_char(cpo.created_at,'YYYY-MM-DD"T"HH24:MI:SS"Z"') AS created_at`;

let sql;
if (latestOnly) {
  sql = `SELECT DISTINCT ON (cpo.competitor_source_id) ${sel}
FROM competitor_price_observations cpo
JOIN competitor_sources cs ON cs.id = cpo.competitor_source_id
${w}
ORDER BY cpo.competitor_source_id, cpo.observed_at DESC`;
} else {
  sql = `SELECT ${sel}
FROM competitor_price_observations cpo
JOIN competitor_sources cs ON cs.id = cpo.competitor_source_id
${w}
ORDER BY cpo.observed_at DESC
LIMIT ${lim}`;
}

return [{ json: { obs_query: sql } }];

const rows = $input.all().map(i => i.json);
// Overall freshness summary
const totalFresh = rows.reduce((s, r) => s + (r.fresh_count || 0), 0);
const totalStale = rows.reduce((s, r) => s + (r.stale_count || 0), 0);
const latestDate = rows.length > 0 ? rows[0].obs_date : null;
return [{
  json: {
    ok: true,
    action: 'market_history',
    count: rows.length,
    total_observations: rows.reduce((s, r) => s + (r.count || 0), 0),
    total_fresh: totalFresh,
    total_stale: totalStale,
    latest_obs_date: latestDate,
    data: rows
  }
}];

const body = $('Webhook').first().json.body || {};
const srcId  = (body.competitor_source_id || '').trim().replace(/'/g, "''");
const dtFrom = (body.stay_date_from || '').trim().replace(/'/g, "''");
const dtTo   = (body.stay_date_to   || '').trim().replace(/'/g, "''");
const price  = parseFloat(body.price_per_night);
const notes  = (body.notes || '').replace(/'/g, "''").trim();

if (!srcId || !dtFrom || !dtTo || !price || price <= 0) {
  const msg = !srcId ? 'competitor_source_id required'
    : !dtFrom ? 'stay_date_from required'
    : !dtTo   ? 'stay_date_to required'
    : 'price_per_night must be > 0';
  return [{ json: { obs_sql: null, err: msg } }];
}

const notesExpr = notes ? `'${notes}'` : 'NULL';

const sql = `INSERT INTO competitor_price_observations
  (competitor_source_id, stay_date_from, stay_date_to,
   price_per_night, collection_method, confidence, notes, observed_at)
VALUES (
  '${srcId}'::uuid,
  '${dtFrom}'::date,
  '${dtTo}'::date,
  ${price},
  'manual_input',
  0.7,
  ${notesExpr},
  NOW()
)
RETURNING id::text AS obs_id`;

return [{ json: { obs_sql: sql, err: null } }];

const prep = $('Prep Add Observation').first().json;
if (prep.err) {
  return [{ json: { ok: false, error: prep.err } }];
}
const r = $input.first().json;
if (!r || !r.obs_id) {
  return [{ json: { ok: false, error: 'insert_failed' } }];
}
return [{ json: { ok: true, action: 'add_competitor_observation', obs_id: r.obs_id, message: 'Наблюдение добавлено' } }];

const body = $('Webhook').first().json.body || {};
const rec_id = (body.recommendation_id || '').trim().replace(/'/g, "''");
if (!rec_id) {
  // Use sentinel UUID so SQL stays valid; Format Export RC will check prep_err
  return [{ json: { prep_err: 'recommendation_id is required', rec_id: '00000000-0000-0000-0000-000000000000' } }];
}
return [{ json: { prep_err: null, rec_id } }];

const prep = $('Prep Export RC').first().json;
if (prep.prep_err) {
  return [{ json: { ok: false, error: prep.prep_err } }];
}

const row = $input.first().json;
if (!row || !row.rec_id) {
  return [{ json: { ok: false, error: 'recommendation not found or status is not approved' } }];
}

// Build prices_obj: keys = each night from date_from to date_to-1 inclusive
const dateFrom = new Date(row.date_from);
const dateTo   = new Date(row.date_to);
const price    = Math.round(row.recommended_price);
const nights   = row.nights || Math.round((dateTo - dateFrom) / 86400000);

const pricesObj = {};
for (let i = 0; i < nights; i++) {
  const d = new Date(dateFrom);
  d.setDate(d.getDate() + i);
  const key = d.toISOString().slice(0, 10);
  pricesObj[key] = price;
}

const dfStr = row.date_from;
const dtStr = row.date_to;
const lastNight = new Date(dateTo);
lastNight.setDate(lastNight.getDate() - 1);
const lastNightStr = lastNight.toISOString().slice(0, 10);
const aptName = row.apartment_name || '';
const lotId   = row.lot_id || '';

// Use \\n (two chars) so n8n JSON serialization is safe; UI can replace with real newlines
const lines = [
  `Открой RealtyCalendar → Управление ценами → ${aptName} (lot_id: ${lotId})`,
  `Установи цену ${price} \u20bd/\u043d\u043e\u0447\u044c \u043d\u0430 \u043f\u0435\u0440\u0438\u043e\u0434 ${dfStr} \u2014 ${lastNightStr} \u0432\u043a\u043b\u044e\u0447\u0438\u0442\u0435\u043b\u044c\u043d\u043e.`,
  `\u041d\u043e\u0447\u0435\u0439: ${nights}`,
  `\u0421\u043a\u043e\u043f\u0438\u0440\u0443\u0439 JSON (prices_obj) \u0434\u043b\u044f batch-\u0432\u0432\u043e\u0434\u0430.`,
  `\u041f\u043e\u0441\u043b\u0435 \u043f\u0440\u0438\u043c\u0435\u043d\u0435\u043d\u0438\u044f \u043d\u0430\u0436\u043c\u0438 "Mark as manually applied" \u0432 Admin \u043f\u0430\u043d\u0435\u043b\u0438.`,
  `Recommendation ID: ${row.rec_id}`,
];

return [{
  json: {
    ok: true,
    action: 'pricing_recommendation_export_rc',
    recommendation_id: row.rec_id,
    apartment_id: row.apartment_id,
    apartment_name: aptName,
    lot_id: lotId,
    date_from: dfStr,
    date_to: dtStr,
    nights,
    recommended_price: price,
    prices_obj: pricesObj,
    manual_instruction: lines.join('\\n'),
    instruction_lines: lines,
  }
}];

parameters.query:
={{ (() => {
const r = $('Format Export RC').first().json;
if (!r.ok) return `SELECT NULL AS audit_id`;
const metaObj = { prices_obj: r.prices_obj, manual_instruction: r.manual_instruction };
const metaEsc = JSON.stringify(metaObj).replace(/'/g, "''");
return `WITH upd AS (
  UPDATE pricing_recommendations SET status='exported', updated_at=NOW()
  WHERE id='${r.recommendation_id}'::uuid AND status='approved'
  RETURNING id::text AS rec_id, apartment_id, date_from, date_to, recommended_price::float
),
audit_ins AS (
  INSERT INTO pricing_action_audit_log
    (recommendation_id, action, previous_status, new_status, apartment_id,
     date_from, date_to, new_price, reason, actor, source, metadata)
  SELECT rec_id::uuid, 'export_rc_manual', 'approved', 'exported',
    apartment_id, date_from, date_to, recommended_price,
    'Exported for manual RC application', 'admin', 'admin_panel',
    '${metaEsc}'::jsonb
  FROM upd
  RETURNING id::text AS audit_id
)
SELECT COALESCE((SELECT audit_id FROM audit_ins LIMIT 1), NULL) AS audit_id`;
})() }}

