parameters.query:
={{ (() => {
const body = $('Webhook').first().json.body || {};
const rec_id = (body.recommendation_id || '').trim().replace(/'/g,"''");
const reason = (body.reason || 'Применено вручную в RealtyCalendar').replace(/'/g,"''");
if (!rec_id) return `SELECT NULL AS audit_id, NULL AS rec_id, 'recommendation_id required' AS err`;
return `WITH old AS (
  SELECT id::text AS rec_id, status AS old_status
  FROM pricing_recommendations WHERE id='${rec_id}'::uuid AND status IN ('exported','approved')
),
upd AS (
  UPDATE pricing_recommendations SET status='manually_applied', updated_at=NOW()
  WHERE id='${rec_id}'::uuid AND status IN ('exported','approved')
  RETURNING id::text AS rec_id, apartment_id, date_from, date_to, recommended_price::float
),
audit_ins AS (
  INSERT INTO pricing_action_audit_log
    (recommendation_id, action, previous_status, new_status, apartment_id,
     date_from, date_to, new_price, reason, actor, source)
  SELECT upd.rec_id::uuid, 'manual_applied', old.old_status, 'manually_applied',
    upd.apartment_id, upd.date_from, upd.date_to, upd.recommended_price,
    '${reason}', 'admin', 'admin_panel'
  FROM upd JOIN old ON old.rec_id = upd.rec_id
  RETURNING id::text AS audit_id
)
SELECT
  COALESCE((SELECT audit_id FROM audit_ins LIMIT 1), NULL) AS audit_id,
  COALESCE((SELECT rec_id FROM upd LIMIT 1), NULL) AS rec_id,
  NULL AS err`;
})() }}

