const r = $input.first().json;
if (r.err) return [{ json: { ok: false, error: r.err } }];
if (!r.audit_id) return [{ json: { ok: false, error: 'recommendation not found' } }];
return [{ json: { ok: true, action: 'pricing_recommendation_mark_apply_failed', rec_id: r.rec_id, audit_id: r.audit_id, message: 'Статус обновлён: apply_failed' } }];

const r = $input.first().json;

const safeInt = (v) => parseInt(v) || 0;
const safeFloat = (v) => v != null ? parseFloat(v) : null;
const safeArr = (v) => {
  if (!v) return [];
  if (typeof v === 'string') try { return JSON.parse(v) || []; } catch { return []; }
  return Array.isArray(v) ? v : [];
};

const draftCount      = safeInt(r.draft_count);
const approvedCount   = safeInt(r.approved_count);
const exportedCount   = safeInt(r.exported_count);
const manualApplied   = safeInt(r.manually_applied_count);
const applyFailed     = safeInt(r.apply_failed_count);
const totalGaps       = safeInt(r.total_gaps);
const totalLoss       = safeFloat(r.total_estimated_loss) || 0;
const activeComp      = safeInt(r.active_competitors);
const staleObs        = safeInt(r.stale_obs);
const freshObs        = safeInt(r.fresh_obs);
const marketMedian    = safeFloat(r.market_median);
const topGaps         = safeArr(r.top_gaps);
const topRecs         = safeArr(r.top_recs);
const latestAudit     = safeArr(r.latest_audit);

// Base price for comparison (owner's typical price)
const BASE_PRICE = 5500;

// Build today_actions
const actions = [];

// HIGH: apply_failed
if (applyFailed > 0) {
  actions.push({
    id: 'apply_failed',
    priority: 'high',
    type: 'failed',
    title: 'Есть ошибки применения',
    description: `${applyFailed} ${applyFailed === 1 ? 'рекомендация не была применена' : 'рекомендации не были применены'}. Проверьте, что пошло не так.`,
    amount: null,
    cta_label: 'Открыть audit log',
    target: '#audit-log'
  });
}

// HIGH: exported waiting for manual apply
if (exportedCount > 0) {
  actions.push({
    id: 'exported',
    priority: 'high',
    type: 'export',
    title: 'Применить вручную в RealtyCalendar',
    description: `${exportedCount} ${exportedCount === 1 ? 'цена подготовлена' : 'цены подготовлены'} для ручного переноса в RealtyCalendar. Нужно применить и отметить.`,
    amount: null,
    cta_label: 'Открыть экспорт',
    target: '#manual-export'
  });
}

// HIGH: gap windows with estimated loss
if (totalGaps > 0 && totalLoss > 0) {
  const topGap = topGaps[0];
  const gapDesc = topGap
    ? `Самое большое: №${topGap.apartment_id}, ${topGap.nights} ${topGap.nights === 1 ? 'ночь' : topGap.nights < 5 ? 'ночи' : 'ночей'} (${topGap.gap_start} — ${topGap.gap_end}).`
    : '';
  actions.push({
    id: 'gaps',
    priority: 'high',
    type: 'gap',
    title: `Маленькие окна: ${totalGaps} ${totalGaps === 1 ? 'окно' : totalGaps < 5 ? 'окна' : 'окон'}`,
    description: `Потенциальная потеря: ${Math.round(totalLoss).toLocaleString('ru-RU')} ₽. ${gapDesc}`,
    amount: Math.round(totalLoss),
    cta_label: 'Смотреть окна',
    target: '#gaps'
  });
}

// MEDIUM: approved but not exported yet
if (approvedCount > 0) {
  actions.push({
    id: 'approved',
    priority: 'medium',
    type: 'export',
    title: 'Одобренная цена ждёт экспорта',
    description: `${approvedCount} ${approvedCount === 1 ? 'рекомендация одобрена' : 'рекомендации одобрены'}, но ещё не подготовлена для переноса в RealtyCalendar.`,
    amount: null,
    cta_label: 'Перейти к рекомендациям',
    target: '#recommendations'
  });
}

// MEDIUM: draft recommendations waiting for approval
if (draftCount > 0) {
  actions.push({
    id: 'draft',
    priority: 'medium',
    type: 'approve',
    title: 'Одобрить рекомендации',
    description: `${draftCount} ${draftCount === 1 ? 'рекомендация ждёт' : 'рекомендации ждут'} вашего решения (одобрить или отклонить).`,
    amount: null,
    cta_label: 'Перейти к рекомендациям',
    target: '#recommendations'
  });
}

// MEDIUM: stale competitor observations
if (staleObs > 0 && freshObs === 0) {
  actions.push({
    id: 'stale_obs',
    priority: 'medium',
    type: 'market',
    title: 'Данные конкурентов устарели',
    description: `${staleObs} ${staleObs === 1 ? 'наблюдение старше' : 'наблюдений старше'} 14 дней. Актуальных данных нет. Рекомендации могут быть неточными.`,
    amount: null,
    cta_label: 'Добавить наблюдение',
    target: '#competitors'
  });
} else if (staleObs > 0) {
  actions.push({
    id: 'stale_obs',
    priority: 'low',
    type: 'market',
    title: 'Часть данных конкурентов устарела',
    description: `${staleObs} из ${staleObs + freshObs} наблюдений старше 14 дней. Обновите при возможности.`,
    amount: null,
    cta_label: 'Добавить наблюдение',
    target: '#competitors'
  });
}

// MEDIUM: market above base price
if (marketMedian != null && marketMedian > BASE_PRICE * 1.1) {
  const diff = Math.round(marketMedian - BASE_PRICE);
  actions.push({
    id: 'market_high',
    priority: 'medium',
    type: 'market',
    title: 'Рынок выше базовой цены',
    description: `Медиана рынка: ${Math.round(marketMedian).toLocaleString('ru-RU')} ₽/сут — на ${diff.toLocaleString('ru-RU')} ₽ выше базы. Возможно поднять цены.`,
    amount: diff,
    cta_label: 'Смотреть данные рынка',
    target: '#market'
  });
}

// LOW / INFO: if no urgent actions
if (actions.length === 0) {
  actions.push({
    id: 'all_good',
    priority: 'low',
    type: 'info',
    title: 'Срочных действий нет',
    description: `Сейчас нет ни маленьких окон, ни ожидающих рекомендаций. Проверьте свежесть данных конкурентов${activeComp > 0 ? ' (' + activeComp + ' активных)' : ''}.`,
    amount: null,
    cta_label: 'Обзор рынка',
    target: '#market'
  });
}

return [{
  json: {
    ok: true,
    action: 'revenue_dashboard',
    summary: {
      total_gaps: totalGaps,
      total_estimated_loss: totalLoss,
      active_competitors: activeComp,
      market_median: marketMedian,
      draft_recommendations: draftCount,
      approved_recommendations: approvedCount,
      exported_recommendations: exportedCount,
      manually_applied_recommendations: manualApplied,
