  }
}];

const r = $input.first().json;

const safeStr = (v) => (v != null && v !== '') ? String(v) : null;
const safeBool = (v) => v === true || v === 't' || v === 'true';

const lastSentAt = safeStr(r.last_sent_at);
const lastHash   = safeStr(r.last_hash);
const within24h  = safeBool(r.within_24h);
const nextAllowed= safeStr(r.next_allowed_at);

// Compute current dashboard hash (same djb2 logic)
const todayActions = parseInt(r.today_actions_count) || 0;
const highCount    = parseInt(r.high_count) || 0;
const mediumCount  = parseInt(r.medium_count) || 0;
const totalGaps    = parseInt(r.total_gaps) || 0;
const totalLoss    = parseFloat(r.total_loss) || 0;
const lowCount     = 0; // gaps counted separately

// Simple hash seed from current state
const contentKey = `high:${highCount}|medium:${mediumCount}|gaps:${totalGaps}|loss:${Math.round(totalLoss)}`;
let h = 0;
for (const c of contentKey) {
  h = ((h << 5) - h + c.charCodeAt(0)) | 0;
}
const currentHash = (h >>> 0).toString(16);

const hashChanged = lastHash !== currentHash;
let antiSpamStatus;
if (!lastSentAt) {
  antiSpamStatus = 'ready';
} else if (within24h && !hashChanged) {
  antiSpamStatus = 'blocked_by_anti_spam';
} else {
  antiSpamStatus = 'ready';
}

const wfActive = safeBool(r.wf_active);

const execStatus = safeStr(r.exec_status);
const result = {
  ok: true,
  workflow: {
    id: safeStr(r.wf_id) || '14',
    name: safeStr(r.wf_name) || '14 — Revenue Notifications',
    active: wfActive,
    schedule: 'daily_09_msk',
    schedule_utc: '06:00'
  },
  anti_spam: {
    last_sent_at: lastSentAt,
    last_hash: lastHash,
    within_24h: within24h,
    next_allowed_at: nextAllowed,
    status: antiSpamStatus
  },
  latest_dashboard: {
    today_actions_count: todayActions,
    high_count: highCount,
    medium_count: mediumCount,
    low_count: lowCount,
    total_gaps: totalGaps,
    current_hash: currentHash,
    hash_changed: hashChanged
  },
  last_execution: execStatus ? {
    status: execStatus === 'success' ? 'success' : execStatus === 'error' ? 'error' : 'unknown',
    started_at: safeStr(r.exec_started_at),
    finished_at: safeStr(r.exec_stopped_at),
    sent: null,
    skip_reason: null
  } : {
    status: 'unknown',
    started_at: null,
    finished_at: null,
    sent: null,
    skip_reason: null
  }
};

return [{ json: result }];

